    """

ALLOWED_FIELDS = {"name", "email", "age"}


def update_profile(user, changes):
    """Update user profile fields from changes dict.

    Invariant: display_name must always equal name.

    Only the fields in ALLOWED_FIELDS are applied. If 'name' is present
    in changes, display_name is updated to match name.

    Args:
        user (dict): existing user profile mapping.
        changes (dict): mapping of fields to update.

    Returns:
        dict: the updated user object (the same dict instance is modified).

    Raises:
        TypeError: if user or changes are not dicts.
    """
    if not isinstance(user, dict) or not isinstance(changes, dict):
        raise TypeError("user and changes must be dicts")

    # If name is being changed, set it first and sync display_name.
    if "name" in changes:
        new_name = changes["name"]
        user["name"] = new_name
        user["display_name"] = new_name

    # Apply other allowed fields (skip 'name' because it's already handled).
    for key, value in changes.items():
        if key == "name":
            continue
        if key in ALLOWED_FIELDS:
            user[key] = value

    return user


def create_user(name, email):
    """Create a new user profile with synced display_name."""
    return {
        "name": name,
        "display_name": name,
        "email": email,
        "age": None,
    }
